actions.script:
import org.moqui.agent.AgentConfigUtil import org.moqui.agent.AgentToolSupport import org.moqui.agent.search.AgentPromptSearchFacade
def startTs = ec.user.nowTimestamp String effectiveIndex = indexName ?: AgentConfigUtil.getString('moqui.agent.prompt.indexName', 'moqui_agent_prompts_v1') String requestedMode = (mode ?: AgentConfigUtil.getNormalizedString('moqui.agent.search.mode', 'hybrid')).toString().toLowerCase()
Map searchResult = new AgentPromptSearchFacade(ec).search(context) resultList = (searchResult.resultList ?: []) as List topDocument = searchResult.topDocument as Map searchDebug = searchResult.searchDebug as Map
boolean elasticTelemetryEnabled = AgentConfigUtil.getBoolean('moqui.agent.elasticTelemetry.enabled', false) if (elasticTelemetryEnabled) { int maxSummaryLength = AgentConfigUtil.getInt('moqui.agent.elasticTelemetry.maxSummaryLength', 2000, 1) boolean includeParameters = AgentConfigUtil.getBoolean('moqui.agent.elasticTelemetry.includeParameters', false) boolean includeResults = AgentConfigUtil.getBoolean('moqui.agent.elasticTelemetry.includeResults', false) String parameterSummary = includeParameters ? AgentToolSupport.toJson([ queryText : queryText, area : area, subArea : subArea, domainObject : domainObject, actionKind : actionKind, operationEffect : operationEffect, currentScreen : currentScreen, currentBusinessObjects : currentBusinessObjects, limit : limit, mode : mode ]) : "queryTextLength=${queryText?.size() ?: 0}; area=${area ?: ''}; subArea=${subArea ?: ''}; domainObject=${domainObject ?: ''}; actionKind=${actionKind ?: ''}; mode=${requestedMode}" String resultSummary = includeResults ? AgentToolSupport.toJson([ found : resultList?.size() ?: 0, topDocument : topDocument, searchDebug : searchDebug ]) : "found=${resultList?.size() ?: 0}; topDocumentId=${topDocument?.documentId ?: ''}; topScore=${topDocument?.score ?: ''}; modeUsed=${searchDebug?.modeUsed ?: requestedMode}" if (parameterSummary?.length() > maxSummaryLength) parameterSummary = parameterSummary.substring(0, maxSummaryLength) if (resultSummary?.length() > maxSummaryLength) resultSummary = resultSummary.substring(0, maxSummaryLength) try { // searchDebug has flattened reranker fields (rerankerProvider, rerankerModel, etc.) boolean rrApplied = Boolean.TRUE.equals(searchDebug?.rerankerApplied) boolean rrFallback = Boolean.TRUE.equals(searchDebug?.rerankerFallbackUsed) ec.service.sync().name('org.moqui.agent.AgentTelemetryServices.create#AgentToolExecutionElasticLog') .disableAuthz() .parameters([ logDate : ec.user.nowTimestamp, userId : ec.user.userId, visitId : ec.user.visitId, mcpSessionId : ec.user.visitId, toolName : 'moqui_search_agent_prompts', documentId : topDocument?.documentId, documentKind : topDocument?.documentKind, area : topDocument?.area ?: area, subArea : topDocument?.subArea ?: subArea, domainObject : topDocument?.domainObject ?: domainObject, actionKind : topDocument?.actionKind ?: actionKind, operationEffect : topDocument?.operationEffect ?: operationEffect, executionChannel : topDocument?.executionChannel, success : true, runningTimeMillis : Math.max(0L, ec.user.nowTimestamp.time - startTs.time) as BigDecimal, resultStatus : 'ok', parameterSummary : parameterSummary, resultSummary : resultSummary, searchMode : (searchDebug?.modeUsed ?: requestedMode), resultCount : (resultList?.size() ?: 0) as Integer, topDocumentId : topDocument?.documentId, topScore : topDocument?.score != null ? (topDocument.score as BigDecimal) : null, indexName : (searchDebug?.indexName ?: effectiveIndex), // LLM reranker telemetry (populated when hybrid_llm_rerank ran) rerankerProvider : searchDebug?.rerankerProvider?.toString(), rerankerModel : searchDebug?.rerankerModel?.toString(), rerankerMode : rrApplied ? 'llm' : (rrFallback ? 'fallback' : null), rerankerCandidateCount : searchDebug?.rerankerCandidateCount as Integer, rerankerSelectedDocumentId : searchDebug?.rerankerSelectedDocumentId?.toString(), rerankerReasonCode : searchDebug?.rerankerReasonCode?.toString(), rerankerConfidence : searchDebug?.rerankerConfidence != null ? (searchDebug.rerankerConfidence as BigDecimal) : null, rerankerLatencyMillis : searchDebug?.rerankerLatencyMillis != null ? (searchDebug.rerankerLatencyMillis as BigDecimal) : null, rerankerFallbackUsed : rrFallback ? 'Y' : 'N' ]).call() } catch (Throwable t) { ec.logger.warn("Unable to write AgentToolExecutionElasticLog telemetry for moqui_search_agent_prompts: ${t.message}") } }

import org.moqui.agent.AgentConfigUtil

int effectiveLimit = Math.min(limit ?: 5, 20)
// Fetch more candidates from each index so RRF has good signal
int fetchLimit = Math.min(effectiveLimit * 3, 30)
int k = rrfK ?: 60

// Search prompt index (screen-first + knowledge docs)
List promptResults = []
try {
    def promptRes = ec.service.sync()
        .name('org.moqui.agent.AgentPromptServices.search#AgentPrompts')
        .parameters([
            queryText : queryText,
            limit     : fetchLimit,
            mode      : searchMode,
            indexName : promptIndexName
        ]).call()
    promptResults = (promptRes?.resultList ?: []) as List
    promptResults = promptResults.collect { Map doc ->
        def result = new LinkedHashMap(doc)
        result.sourceIndex = 'moqui_agent_prompts_v1'
        result
    }
} catch (Exception e) {
    ec.logger.warn("search#AllDocuments: prompt index search failed: ${e.message}")
}

// Search artifact index (services, entities, screens, XSD)
List artifactResults = []
try {
    def artifactRes = ec.service.sync()
        .name('org.moqui.agent.RagServices.search#Artifacts')
        .parameters([
            queryText : queryText,
            limit     : fetchLimit,
            searchMode: searchMode,
            indexName : artifactIndexName
        ]).call()
    def rawHits = (artifactRes?.resultList ?: []) as List
    artifactResults = rawHits.collect { Map hit ->
        def src = (hit._source ?: hit) as Map
        def result = new LinkedHashMap(src)
        result.sourceIndex = 'moqui_artifacts_v1'
        if (hit._score != null) result.score = hit._score
        result
    }
} catch (Exception e) {
    ec.logger.warn("search#AllDocuments: artifact index search failed: ${e.message}")
}

promptCount = promptResults.size() as Integer
artifactCount = artifactResults.size() as Integer

// Reciprocal Rank Fusion: rrfScore(d) = sum_over_lists( 1 / (k + rank_in_list) )
// rank is 1-based position in the score-sorted list from each index
Map<String, Double> rrfScores = new LinkedHashMap<>()
Map<String, Map> docById = new LinkedHashMap<>()

Closure applyList = { List results, String idField ->
    results.sort { a, b -> (b.score ?: 0) <=> (a.score ?: 0) }
    results.eachWithIndex { Map doc, int idx ->
        String docId = (doc[idField] ?: doc.documentId ?: doc.artifactName ?: "${doc.sourceIndex}:${idx}")?.toString()
        if (!docId) return
        rrfScores[docId] = (rrfScores[docId] ?: 0.0d) + (1.0d / (k + idx + 1))
        if (!docById.containsKey(docId)) docById[docId] = doc
    }
}

applyList(promptResults, 'documentId')
applyList(artifactResults, 'artifactName')

resultList = rrfScores.entrySet()
    .sort { a, b -> b.value <=> a.value }
    .take(effectiveLimit)
    .collect { entry ->
        Map doc = new LinkedHashMap(docById[entry.key] ?: [:])
        doc.rrfScore = entry.value
        doc
    }
